// src/components/MementoMori.ts
init_constants();
function resolveExpectancy(settings) {
  const stats = settings.personalStats;
  if (stats.lifeExpectancy > 0)
    return stats.lifeExpectancy;
  return stats.gender === "female" ? LIFE_EXPECTANCY_FEMALE : LIFE_EXPECTANCY_MALE;
}
function calculateMementoData(settings) {
  const stats = settings.personalStats;
  if (!stats.birthdate)
    return null;
  const expectancy = resolveExpectancy(settings);
  const totalWeeks = Math.floor(expectancy * 52.1775);
  const birthDate = new Date(stats.birthdate);
  if (isNaN(birthDate.getTime()))
    return null;
  const weeksLived = Math.floor(
    (Date.now() - birthDate.getTime()) / (7 * 24 * 60 * 60 * 1e3)
  );
  const weeksLeft = Math.max(0, totalWeeks - weeksLived);
  return { totalWeeks, weeksLived, weeksLeft, expectancy, birthDate };
}
function renderMementoMoriFull(root, settings, staggerIdx, onEditExpectancy) {
  const data = calculateMementoData(settings);
  const section = root.createDiv({ cls: "olen-card olen-memento-mori-card" });
  section.style.setProperty("--i", String(staggerIdx));
  const header = section.createDiv({ cls: "olen-memento-mori-header" });
  header.createEl("div", { cls: "olen-heading", text: "MEMENTO MORI" });
  if (onEditExpectancy) {
    const gear = header.createEl("button", {
      cls: "olen-memento-mori-gear",
      text: "\u2699"
    });
    gear.setAttribute("aria-label", "Override life expectancy");
    gear.addEventListener("click", (e) => {
      e.stopPropagation();
      onEditExpectancy();
    });
  }
  if (!data) {
    section.createEl("div", {
      cls: "olen-data-sm",
      text: "Set your birthdate in Settings \u2192 Personal Stats to see your life in weeks.",
      attr: { style: "opacity: 0.6; padding: 16px 0;" }
    });
    return;
  }
  const statsLine = section.createDiv({ cls: "olen-memento-mori-stats" });
  statsLine.createEl("span", {
    text: `You have lived ${data.weeksLived.toLocaleString()} weeks.`
  });
  statsLine.createEl("span", {
    text: ` You have ~${data.weeksLeft.toLocaleString()} weeks left.`,
    attr: { style: "opacity: 0.7;" }
  });
  const yearsTotal = Math.ceil(data.totalWeeks / 52);
  const grid = section.createDiv({ cls: "olen-memento-mori-grid" });
  for (let year = 0; year < yearsTotal; year++) {
    for (let week = 0; week < 52; week++) {
      const weekIndex = year * 52 + week;
      if (weekIndex >= data.totalWeeks)
        break;
      const dot = grid.createDiv({ cls: "olen-memento-mori-dot" });
      if (weekIndex < data.weeksLived) {
        dot.classList.add("olen-memento-mori-dot-lived");
      } else if (weekIndex === data.weeksLived) {
        dot.classList.add("olen-memento-mori-dot-current");
      }
    }
  }
  const countdown = section.createDiv({ cls: "olen-memento-mori-countdown" });
  const remainingMs = data.weeksLeft * 7 * 24 * 60 * 60 * 1e3;
  const targetDate = new Date(Date.now() + remainingMs);
  const diffMs = targetDate.getTime() - Date.now();
  const years = Math.floor(diffMs / (365.25 * 24 * 60 * 60 * 1e3));
  const months = Math.floor(
    diffMs % (365.25 * 24 * 60 * 60 * 1e3) / (30.44 * 24 * 60 * 60 * 1e3)
  );
  const days = Math.floor(
    diffMs % (30.44 * 24 * 60 * 60 * 1e3) / (24 * 60 * 60 * 1e3)
  );
  const hours = Math.floor(
    diffMs % (24 * 60 * 60 * 1e3) / (60 * 60 * 1e3)
  );
  const units = [
    { value: years, label: "years" },
    { value: months, label: "months" },
    { value: days, label: "days" },
    { value: hours, label: "hours" }
  ];
  for (const unit of units) {
    const cell = countdown.createDiv({ cls: "olen-memento-mori-countdown-cell" });
    cell.createEl("div", { cls: "olen-memento-mori-countdown-value", text: String(unit.value) });
    cell.createEl("div", { cls: "olen-memento-mori-countdown-label", text: unit.label });
  }
}
function renderMementoMoriCompact(root, settings, staggerIdx) {
  const data = calculateMementoData(settings);
  if (!data)
    return;
  const card = root.createDiv({ cls: "olen-card olen-memento-mori-compact" });
  card.style.setProperty("--i", String(staggerIdx));
  const percent = Math.min(100, Math.round(data.weeksLived / data.totalWeeks * 100));
  const row = card.createDiv({ cls: "olen-memento-mori-compact-row" });
  row.createEl("span", {
    cls: "olen-heading",
    text: "MEMENTO MORI"
  });
  const barWrap = row.createDiv({ cls: "olen-memento-mori-compact-bar" });
  const fill = barWrap.createDiv({ cls: "olen-memento-mori-compact-fill" });
  fill.style.width = `${percent}%`;
  row.createEl("span", {
    cls: "olen-data-sm",
    text: `${data.weeksLeft.toLocaleString()} weeks left`,
    attr: { style: "white-space: nowrap;" }
  });
}

// src/components/SundayCheckin.ts
function shouldShowSundayBanner(settings, now) {
  const checkin = settings.sundayCheckin;
  if (!checkin.enabled)
    return false;
  const isSunday = now.getDay() === 0;
  if (!isSunday)
    return false;
  const todayStr = now.toISOString().slice(0, 10);
  if (checkin.lastCheckinDate === todayStr)
    return false;
  return true;
}
function renderSundayBanner(root, settings, staggerIdx, callbacks) {
  const banner = root.createDiv({ cls: "olen-card olen-sunday-banner" });
  banner.style.setProperty("--i", String(staggerIdx));
  const inner = banner.createDiv({ cls: "olen-sunday-banner-inner" });
  inner.createEl("div", {
    cls: "olen-sunday-banner-text",
    text: "Olen wants to speak to you"
  });
  const actions = inner.createDiv({ cls: "olen-sunday-banner-actions" });
  const dismissBanner = (callback) => {
    banner.classList.add("olen-sunday-banner-dismissing");
    setTimeout(callback, 400);
  };
  const letInBtn = actions.createEl("button", {
    cls: "olen-btn olen-btn-primary",
    text: "Let him in"
  });
  letInBtn.addEventListener("click", (e) => {
    e.stopPropagation();
    dismissBanner(() => callbacks.onLetHimIn());
  });
  const ignoreBtn = actions.createEl("button", {
    cls: "olen-btn olen-btn-ghost",
    text: "Ignore"
  });
  ignoreBtn.addEventListener("click", (e) => {
    e.stopPropagation();
    dismissBanner(() => callbacks.onIgnore());
  });
}
function renderOptOutModal(onTurnOff, onKeep) {
  const overlay = document.createElement("div");
  overlay.className = "olen-sunday-optout-overlay";
  const sheet = document.createElement("div");
  sheet.className = "olen-sunday-optout-sheet";
  const title = document.createElement("div");
  title.className = "olen-sunday-optout-title";
  title.textContent = "Do you want Olen to go away?";
  sheet.appendChild(title);
  const desc = document.createElement("div");
  desc.className = "olen-sunday-optout-desc";
  desc.textContent = "This will stop Olen from checking in with you on Sundays. You can re-enable this anytime in Settings \u2192 Advanced.";
  sheet.appendChild(desc);
  const actions = document.createElement("div");
  actions.className = "olen-sunday-optout-actions";
  const dismissOverlay = (callback) => {
    overlay.style.opacity = "0";
    setTimeout(() => {
      overlay.remove();
      callback();
    }, 400);
  };
  const turnOffBtn = document.createElement("button");
  turnOffBtn.className = "olen-btn olen-btn-ghost";
  turnOffBtn.textContent = "Turn off";
  turnOffBtn.addEventListener("click", () => {
    dismissOverlay(onTurnOff);
  });
  actions.appendChild(turnOffBtn);
  const keepBtn = document.createElement("button");
  keepBtn.className = "olen-btn olen-btn-primary";
  keepBtn.textContent = "No, keep him";
  keepBtn.addEventListener("click", () => {
    dismissOverlay(onKeep);
  });
  actions.appendChild(keepBtn);
  sheet.appendChild(actions);
  overlay.appendChild(sheet);
  overlay.addEventListener("click", (e) => {
    if (e.target === overlay) {
      dismissOverlay(onKeep);
    }
  });
  document.body.appendChild(overlay);
}

